import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';

function App() {
  const [etapa, setEtapa] = useState('login'); 
  const [modo, setModo] = useState(''); 
  const [codigo, setCodigo] = useState("");
  const [usuario, setUsuario] = useState(null);
  const [mensagem, setMensagem] = useState("Aguardando crachá...");
  const [processando, setProcessando] = useState(false);
  const [relatorio, setRelatorio] = useState([]);
  const inputRef = useRef(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, [etapa, modo]);

  const handleKeyPress = async (e) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      const valorLimpo = codigo.replace(/\D/g, ''); // Limpa o "e" e outros caracteres
      if (!valorLimpo || processando) { setCodigo(""); return; }

      setProcessando(true);
      try {
        if (etapa === 'login') await realizarLogin(valorLimpo);
        else if (etapa === 'acao') await processarAcao(valorLimpo);
      } finally {
        setCodigo("");
        setTimeout(() => setProcessando(false), 800);
      }
    }
  };

  const realizarLogin = async (codBarras) => {
    try {
      const res = await axios.post('http://localhost:3001/login', { codBarras });
      setUsuario(res.data);
      setEtapa('escolha');
      setMensagem(`Olá, ${res.data.nome}!`);
    } catch (err) { setMensagem("❌ Crachá não cadastrado."); }
  };

  const processarAcao = async (ferramentacod) => {
    const url = modo === 'retirada' ? '/emprestimo/retirada' : '/emprestimo/devolucao';
    try {
      const res = await axios.post(`http://localhost:3001${url}`, { 
        usuarioId: usuario.id, 
        ferramentacod 
      });
      setMensagem(`✅ ${res.data}`);
      setTimeout(() => {
        setMensagem(modo === 'retirada' ? "Bipe a próxima ferramenta" : "Bipe o próximo retorno");
      }, 2500);
    } catch (err) { setMensagem("❌ Erro na operação."); }
  };

  const verPainelAdmin = async () => {
    setEtapa('admin');
    setMensagem("Painel de Controle Admin");
    try {
      const res = await axios.get('http://localhost:3001/admin/status-ferramentas');
      setRelatorio(res.data);
    } catch (err) { console.error(err); }
  };

  return (
    <div style={styles.container}>
      <img src="/logo-tsea.png" style={{ width: '150px' }} alt="logo" />
      <div style={styles.card}>
        <h2 style={{ color: '#002d62' }}>{mensagem}</h2>

        {etapa === 'login' && (
          <input ref={inputRef} value={codigo} onChange={(e) => setCodigo(e.target.value)} onKeyDown={handleKeyPress} placeholder="Scanner..." style={styles.input} />
        )}

        {etapa === 'escolha' && (
          <div style={styles.column}>
            <button onClick={() => { setModo('retirada'); setEtapa('acao'); setMensagem("Modo Retirada Ativo"); }} style={{...styles.button, backgroundColor: '#0055ff'}}>RETIRAR FERRAMENTAS</button>
            <button onClick={() => { setModo('devolucao'); setEtapa('acao'); setMensagem("Modo Devolução Ativo"); }} style={{...styles.button, backgroundColor: '#28a745'}}>DEVOLVER FERRAMENTAS</button>
            
            {usuario?.tipo === 'admin' && (
              <button onClick={verPainelAdmin} style={{...styles.button, backgroundColor: '#6f42c1'}}>📊 PAINEL ADMIN</button>
            )}
            
            <button onClick={() => { setUsuario(null); setEtapa('login'); setMensagem("Aguardando crachá..."); }} style={styles.btnSair}>ENCERRAR SESSÃO</button>
          </div>
        )}

        {etapa === 'acao' && (
          <div style={styles.column}>
            <input ref={inputRef} value={codigo} onChange={(e) => setCodigo(e.target.value)} onKeyDown={handleKeyPress} placeholder="Bipe a ferramenta..." style={styles.input} />
            <button onClick={() => setEtapa('escolha')} style={styles.btnLink}>← Voltar para opções</button>
          </div>
        )}

        {etapa === 'admin' && (
          <div>
            <table style={styles.table}>
              <thead>
                <tr><th>Item</th><th>Status</th><th>Com quem?</th></tr>
              </thead>
              <tbody>
                {relatorio.map((r, i) => (
                  <tr key={i}><td>{r.nome}</td><td>{r.status}</td><td>{r.usuario_atual || '--'}</td></tr>
                ))}
              </tbody>
            </table>
            <button onClick={() => setEtapa('escolha')} style={styles.buttonGray}>Voltar</button>
          </div>
        )}
      </div>
    </div>
  );
}

const styles = {
  container: { textAlign: 'center', padding: '50px', backgroundColor: '#f4f7f9', minHeight: '100vh', fontFamily: 'sans-serif' },
  card: { padding: '40px', backgroundColor: 'white', borderRadius: '15px', display: 'inline-block', boxShadow: '0 4px 10px rgba(0,0,0,0.1)', minWidth: '400px' },
  input: { padding: '15px', fontSize: '20px', textAlign: 'center', borderRadius: '10px', border: '2px solid #0055ff', width: '300px' },
  button: { padding: '20px', color: 'white', border: 'none', borderRadius: '8px', margin: '10px', cursor: 'pointer', fontWeight: 'bold', width: '300px' },
  buttonGray: { padding: '10px', backgroundColor: '#666', color: 'white', border: 'none', borderRadius: '5px', marginTop: '20px', cursor: 'pointer' },
  column: { display: 'flex', flexDirection: 'column', alignItems: 'center' },
  btnSair: { marginTop: '20px', background: 'none', border: '1px solid #dc3545', color: '#dc3545', padding: '10px', borderRadius: '5px', cursor: 'pointer' },
  btnLink: { background: 'none', border: 'none', color: '#0055ff', marginTop: '20px', cursor: 'pointer', fontWeight: 'bold' },
  table: { width: '100%', borderCollapse: 'collapse', marginTop: '20px', textAlign: 'left' }
};

export default App;
